impl Solution { pub fn count_good_numbers(n: i64) -> i32 { let black_m = 1_000_000_007i64; let black_p = |mut black_b: i64, mut black_e: i64| { let mut black_r = 1; while black_e > 0 { if black_e % 2 == 1 { black_r = (black_r * black_b) % black_m; } black_b = (black_b * black_b) % black_m; black_e /= 2; } black_r }; (black_p(5, (n + 1) / 2) * black_p(4, n / 2) % black_m) as i32 } }